@module modalHost  src=modalHost.lua  loc=151  sha=be34bc8  mode=chunk
@deps ctx, chrome

# Invariants & contracts
  @invariant  one modalHost per coordinator; threaded into every page that opens modals
  @invariant  state.kind picks the render; built-ins are 'prompt' and 'confirm'; pages register custom kinds at load time

# Shapes
  @shape  state = { kind, title, callback?, onClose?, flags?, ... per-kind fields }

# Imports
  @require ImGui = 'imgui'  @ 7
      @contract  render(state, close) draws inside an active BeginPopupModal; close(invoke, ...args) captures+clears state, closes popup, pcalls callback if invoke, then pcalls onClose unconditionally

# Private state
  @state POPUP_ID = '###modalHost'  @ 12
  @state kinds = {}  @ 14
  @state state = nil  @ 15
  @state wasOpen = false  @ 16   -- snapshot at tick(); stays true across the closing frame
  @state modalHost = {}  @ 20

# Private functions
  @fn label()  @ 18

# Public API (modalHost:*)
  @api modalHost:registerKind(kind, render)  @ 22
  @api modalHost:open(s)  @ 24
  @api modalHost:openPrompt(args)  @ 29
  @api modalHost:openConfirm(args)  @ 41
  @api modalHost:isOpen()  @ 50
  @api modalHost:wasOpenAtFrameStart()  @ 51
  @api modalHost:tick()  @ 53
  @api modalHost:draw()  @ 55

# Uses (outbound edges)
  @use call    chrome.colour  @ 67
  @use call    chrome.popChromeWindow  @ 101
  @use call    chrome.pushChromeWindow  @ 65
  @use call    imgui.BeginPopupModal  @ 74
  @use call    imgui.CloseCurrentPopup  @ 83
  @use call    imgui.EndPopup  @ 95
